//! benchmark tests: an equivalent program in HolyC and in C, checked for
//! identical output and timed against each other.
//!
//! One `#[test]` per `tests/bench/<name>/` directory (each holds `prog.hc` + `prog.c`),
//! generated by `build.rs` into `$OUT_DIR/bench.rs`. Each test compiles both with the
//! host toolchain (HolyC via the native backend, C via `cc -O2`), asserts byte-identical
//! stdout (the only hard failure), then times `ITERS` runs of each and prints the
//! HolyC-vs-C ratio. Timing never fails the test, but a substantial slowdown emits a
//! warning. Host-gated: runs only where both binaries can be built and executed.

mod support;

use std::path::PathBuf;
use std::process::Command;

/// Iterations per side when timing. Each bench program loops enough internal work that one
/// run is milliseconds, so process-spawn overhead doesn't dominate.
const ITERS: u32 = 15;

/// Warn (do not fail) when HolyC is more than this many times slower than C.
const WARN_RATIO: f64 = 5.0;

fn bench_dir(name: &str) -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("bench")
        .join(name)
}

fn run_comparison(name: &str) {
    if !support::native_host_available() || !support::cc_available() {
        eprintln!("bench {name}: skipped (needs a runnable host backend + cc)");
        return;
    }
    let dir = bench_dir(name);

    // Build the HolyC program for the host target.
    let hc_src = std::fs::read_to_string(dir.join("prog.hc")).expect("prog.hc readable");
    let program = hcc::parser::parse_with(&hc_src, &dir, &[])
        .unwrap_or_else(|e| panic!("{name}: HolyC parse failed: {e}"));
    assert!(
        hcc::sema::check_program(&program).is_empty(),
        "{name}: HolyC sema errors"
    );
    let hc_bin = support::temp_path(&format!("bench-{name}-hc"));
    assert!(
        support::build_native_to(&program, &hc_bin),
        "{name}: no host backend to build the HolyC binary"
    );

    // Compile the C reference with cc -O2.
    let c_bin = support::temp_path(&format!("bench-{name}-c"));
    let cc = Command::new("cc")
        .arg("-O2")
        .arg("-o")
        .arg(&c_bin)
        .arg(dir.join("prog.c"))
        .status()
        .unwrap_or_else(|e| panic!("{name}: cc failed to spawn: {e}"));
    assert!(cc.success(), "{name}: cc -O2 failed to compile prog.c");

    // Parity: identical stdout (the only hard failure).
    let hc_out = support::run_capture(&hc_bin);
    let c_out = support::run_capture(&c_bin);
    assert_eq!(
        hc_out,
        c_out,
        "{name}: HolyC and C stdout differ\n  holyc: {:?}\n      c: {:?}",
        String::from_utf8_lossy(&hc_out),
        String::from_utf8_lossy(&c_out),
    );

    // Timing: informational. Never fails; warns on a substantial slowdown.
    let t_hc = support::time_runs(&hc_bin, ITERS);
    let t_c = support::time_runs(&c_bin, ITERS);
    let ratio = t_hc.as_secs_f64() / t_c.as_secs_f64().max(1e-9);
    eprintln!(
        "bench {name}: HolyC {:.1}ms  C {:.1}ms  ({ratio:.2}x)  [{ITERS} runs each]",
        t_hc.as_secs_f64() * 1e3 / ITERS as f64,
        t_c.as_secs_f64() * 1e3 / ITERS as f64,
    );
    if ratio > WARN_RATIO {
        eprintln!(
            "bench {name}: WARNING — HolyC is {ratio:.1}x slower than C (> {WARN_RATIO:.0}x)"
        );
    }

    let _ = std::fs::remove_file(&hc_bin);
    let _ = std::fs::remove_file(&c_bin);
}

// One `#[test] fn bench_<name>` per `tests/bench/<name>/` (prog.hc + prog.c), generated at
// compile time. Adding a pair needs a rebuild to be re-globbed (`touch tests/comparison.rs`).
hcc_test_macros::comparison_cases!();
